type hugoQuizInt int

func (value *hugoQuizInt) UnmarshalJSON(data []byte) error {
	var intValue int
	if err := json.Unmarshal(data, &intValue); err == nil {
		*value = hugoQuizInt(intValue)
		return nil
	}

	var stringValue string
	if err := json.Unmarshal(data, &stringValue); err != nil {
		return fmt.Errorf("decode quiz integer from %q: %w", string(data), err)
	}

	normalized := html.UnescapeString(strings.TrimSpace(stringValue))
	normalized = strings.Trim(normalized, `"`)
	if normalized == "" {
		*value = 0
		return nil
	}

	intValue, err := strconv.Atoi(normalized)
	if err != nil {
		return fmt.Errorf("parse quiz integer %q: %w", normalized, err)
	}

	*value = hugoQuizInt(intValue)
	return nil
}

func (quiz *Quiz) UnmarshalJSON(data []byte) error {
	if looksLikeHugoQuiz(data) {
		var legacy HugoQuiz
		if err := json.Unmarshal(data, &legacy); err != nil {
			return err
		}

		canonical, err := legacy.ToCanonical()
		if err != nil {
			return err
		}

		*quiz = canonical
		return nil
	}

	type canonicalQuiz Quiz
	var alias canonicalQuiz
	if err := json.Unmarshal(data, &alias); err != nil {
		return err
	}

	*quiz = Quiz(alias)
	return nil
}

func (quiz HugoQuiz) ToCanonical() (Quiz, error) {
	quizID, err := parseRequiredUUID("id", quiz.ID)
	if err != nil {
		return Quiz{}, err
	}

	orgID, err := parseRequiredUUID("org_id", quiz.OrgID)
	if err != nil {
		return Quiz{}, err
	}

	questions := make([]Question, len(quiz.Questions))
	for index, question := range quiz.Questions {
		canonicalQuestion, err := quiz.toCanonicalQuestion(index, question)
		if err != nil {
			return Quiz{}, err
		}
		questions[index] = canonicalQuestion
	}

	prerequisites := make([]Parent, len(quiz.Prerequisites))
	for index, prerequisite := range quiz.Prerequisites {
		canonicalParent, err := quiz.toCanonicalParent(prerequisite)
		if err != nil {
			return Quiz{}, err
		}
		prerequisites[index] = canonicalParent
	}

	var parent *Parent
	if quiz.Parent != nil {
		if !quiz.Parent.isZero() {
			canonicalParent, err := quiz.toCanonicalParent(*quiz.Parent)
			if err != nil {
				return Quiz{}, err
			}
			parent = &canonicalParent
		}
	}

	nextPage, err := quiz.toCanonicalParent(quiz.NextPage)
	if err != nil {
		return Quiz{}, err
	}

	return Quiz{
		Date:                 quiz.Date,
		Description:          quiz.Description,
		Draft:                quiz.Draft,
		FilePath:             quiz.FilePath,
		Final:                quiz.Final,
		ID:                   quizID,
		Lastmod:              quiz.Lastmod,
		Layout:               quiz.Layout,
		MaxAttempts:          quiz.MaxAttempts,
		NextPage:             nextPage,
		OrgId:                orgID,
		Parent:               parent,
		PassPercentage:       quiz.PassPercentage,
		Permalink:            quiz.Permalink,
		Prerequisites:        prerequisites,
		Questions:            questions,
		RelPermalink:         quiz.RelPermalink,
		Section:              quiz.Section,
		Slug:                 quiz.Slug,
		TimeLimit:            int(quiz.TimeLimit),
		Title:                quiz.Title,
		TotalMarks:           quiz.TotalMarks,
		TotalQuestionSets:    quiz.TotalQuestionSets,
		TotalQuestions:       quiz.TotalQuestions,
		TotalQuestionsInBank: quiz.TotalQuestionsInBank,
		Type:                 quiz.Type,
	}, nil
}

func looksLikeHugoQuiz(data []byte) bool {
	var object map[string]json.RawMessage
	if err := json.Unmarshal(data, &object); err != nil {
		return false
	}

	legacyTopLevelKeys := []string{
		"file_path",
		"pass_percentage",
		"time_limit",
		"max_attempts",
		"total_questions",
		"total_questions_in_bank",
		"total_question_sets",
		"total_marks",
		"next_page",
	}

	for _, key := range legacyTopLevelKeys {
		if _, ok := object[key]; ok {
			return true
		}
	}

	rawQuestions, ok := object["questions"]
	if !ok {
		return false
	}

	var questions []map[string]json.RawMessage
	if err := json.Unmarshal(rawQuestions, &questions); err != nil {
		return false
	}

	for _, question := range questions {
		if _, ok := question["correct_answer"]; ok {
			return true
		}
		if _, ok := question["multiple_answers"]; ok {
			return true
		}

		rawOptions, ok := question["options"]
		if !ok {
			continue
		}

		var options []map[string]json.RawMessage
		if err := json.Unmarshal(rawOptions, &options); err != nil {
			continue
		}

		for _, option := range options {
			if _, ok := option["is_correct"]; ok {
				return true
			}
		}
	}

	return false
}

func (quiz HugoQuiz) toCanonicalQuestion(index int, question HugoQuestion) (Question, error) {
	questionID := quiz.deriveQuestionUUID(question.ID, index, question.Text)
	options := make([]QuestionOption, len(question.Options))
	for optionIndex, option := range question.Options {
		options[optionIndex] = QuestionOption{
			ID:        quiz.deriveOptionUUID(questionID, option.ID, optionIndex, option.Text),
			IsCorrect: option.isCorrect(),
			Text:      option.Text,
		}
	}

	questionType := normalizeLegacyQuestionType(question.Type)
	return Question{
		CorrectAnswer:   question.correctAnswer(),
		ID:              questionID,
		Marks:           question.Marks,
		MultipleAnswers: question.multipleAnswers(questionType),
		Options:         options,
		Text:            question.Text,
		Type:            questionType,
	}, nil
}

func (quiz HugoQuiz) toCanonicalParent(parent HugoParent) (Parent, error) {
	if parent.isZero() {
		return Parent{}, nil
	}

	return Parent{
		ID:           quiz.deriveContentUUID(parent.ID, parent.RelPermalink, parent.Title, parent.Type),
		RelPermalink: parent.RelPermalink,
		Title:        parent.Title,
		Type:         parent.Type,
	}, nil
}

func (parent HugoParent) isZero() bool {
	return parent.ID == "" && parent.Title == "" && parent.RelPermalink == "" && parent.Type == ""
}

func (question HugoQuestion) correctAnswer() string {
	if question.CorrectAnswer != "" {
		return question.CorrectAnswer
	}
	return question.CorrectAnswerCamel
}

func (question HugoQuestion) multipleAnswers(questionType QuestionType) *bool {
	if question.MultipleAnswers != nil {
		return question.MultipleAnswers
	}
	if question.MultipleAnswersLegacy != nil {
		return question.MultipleAnswersLegacy
	}

	switch questionType {
	case QuestionTypeMultipleAnswers:
		value := true
		return &value
	case QuestionTypeSingleAnswer:
		value := false
		return &value
	default:
		return nil
	}
}

func (option HugoQuestionOption) isCorrect() bool {
	if option.IsCorrectCamel != nil {
		return *option.IsCorrectCamel
	}
	return option.IsCorrect
}

func normalizeLegacyQuestionType(raw string) QuestionType {
	return QuestionType(strings.ReplaceAll(strings.TrimSpace(raw), "_", "-"))
}

func parseRequiredUUID(field, raw string) (openapi_types.UUID, error) {
	value, err := uuid.Parse(strings.TrimSpace(raw))
	if err != nil {
		return uuid.Nil, fmt.Errorf("parse academy quiz %s UUID %q: %w", field, raw, err)
	}

	return value, nil
}

func (quiz HugoQuiz) deriveContentUUID(rawID, relPermalink, title, contentType string) openapi_types.UUID {
	if parsed, err := uuid.Parse(strings.TrimSpace(rawID)); err == nil {
		return parsed
	}

	return uuid.NewSHA1(uuid.NameSpaceURL, []byte(strings.Join([]string{
		"academy-theme",
		"v1beta2",
		"content",
		quiz.OrgID,
		relPermalink,
		title,
		contentType,
		rawID,
	}, "\x1f")))
}

func (quiz HugoQuiz) deriveQuestionUUID(rawID string, index int, text string) openapi_types.UUID {
	if parsed, err := uuid.Parse(strings.TrimSpace(rawID)); err == nil {
		return parsed
	}

	return uuid.NewSHA1(uuid.NameSpaceURL, []byte(strings.Join([]string{
		"academy-theme",
		"v1beta2",
		"question",
		quiz.ID,
		quiz.FilePath,
		strconv.Itoa(index),
		rawID,
		text,
	}, "\x1f")))
}

func (quiz HugoQuiz) deriveOptionUUID(questionID openapi_types.UUID, rawID string, index int, text string) openapi_types.UUID {
	if parsed, err := uuid.Parse(strings.TrimSpace(rawID)); err == nil {
		return parsed
	}

	return uuid.NewSHA1(uuid.NameSpaceURL, []byte(strings.Join([]string{
		"academy-theme",
		"v1beta2",
		"option",
		questionID.String(),
		strconv.Itoa(index),
		rawID,
		text,
	}, "\x1f")))
}
